import json
P = json.load(open('work/preds.json'))

# Protected set: genuine research/structural signal -> keep current mass (already calibrated)
protected = {
 "883856",  # Sarvarov confirmed
 "459037","703511",  # AFCON bracket-confirmed
 "946810","951896","348570","221278",  # awards/sports favorites w/ real signal
 "291796","783773","666021","318661","398988","325000",  # strong single-topic signal
}

# Specific honest re-sets for the 2 resolving tomorrow
P["468637"] = {"United Arab Emirates":0.10, "Sri Lanka":0.07, "Pakistan":0.05}
P["651727"] = {"Edmundo Gonzalez Urrutia":0.12, "Maria Corina Machado":0.08, "Juan Guaido":0.04}

changed = {}
for q,od in P.items():
    if q in protected:
        continue
    if q in ("468637","651727"):
        changed[q]=od  # already set above
        continue
    # scale down speculative
    new = {}
    for k,v in od.items():
        nv = round(v*0.45,3)
        if nv >= 0.03:
            new[k]=nv
    if not new:  # keep at least top guess scaled
        top = max(od.items(), key=lambda x:x[1])
        new[top[0]] = max(0.03, round(top[1]*0.45,3))
    P[q] = new
    changed[q]=new

# validate
errs=[]
for q,od in P.items():
    s=sum(od.values())
    if s>1.0+1e-9: errs.append((q,"sum",round(s,3)))
    if len(od)>5: errs.append((q,"count",len(od)))
    for k,v in od.items():
        if v<=0: errs.append((q,"zero",k))
print("total:",len(P),"errors:",errs[:10])
# distribution of total masses
import statistics
totals=[round(sum(od.values()),3) for od in P.values()]
print("total-mass: min",min(totals),"median",statistics.median(totals),"max",max(totals))
json.dump(P, open('work/preds.json','w'), indent=1, ensure_ascii=False)
json.dump(changed, open('work/changed.json','w'), indent=1, ensure_ascii=False)
print("changed:",len(changed))
EOF

